#include <stdio.h>
#include <string.h>
#include "esp_system.h"
#include "esp_wifi.h"
#include "esp_http_client.h"

#define FIRMWARE_URL_MAX_LEN 256
#define FIRMWARE_FILE_NAME "firmware.bin"

void http_download(const char *url, const char *filename) {
    esp_http_client_config_t config = {
        .url = url,
        .method = HTTP_METHOD_GET,
        .timeout_ms = 10000,
        .buffer_max_size = 1024
    };

    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (client == NULL) {
        printf("Failed to initialize http client\n");
        return;
    }

    int status_code = esp_http_client_perform(client);
    if (status_code != 200) {
        printf("Failed to download firmware, status code: %d\n", status_code);
        return;
    }

    char *data = malloc(esp_http_client_get_response_size(client));
    if (data == NULL) {
        printf("Memory allocation failed\n");
        return;
    }

    esp_http_client_read(client, data, esp_http_client_get_response_size(client));

    FILE *file = fopen(filename, "wb");
    if (file == NULL) {
        printf("Failed to open file for writing\n");
        free(data);
        return;
    }

    fwrite(data, 1, esp_http_client_get_response_size(client), file);
    fclose(file);

    free(data);
}

void update_firmware(const char *url) {
    http_download(url, FIRMWARE_FILE_NAME);
    printf("Firmware downloaded and saved to flash memory\n");
    esp_restart();
}

